mcp:tool-listener.mcp:parameters-schema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "partnerName": { "type": "string", "description": "Partner profile name in Partner Manager (must already exist)" },
    "certificateName": { "type": "string", "description": "Display name for the certificate (e.g. freshcorner-as2)" },
    "certificateType": { "type": "string", "enum": ["PUBLIC", "IDENTITY_KEY"], "description": "PUBLIC = public cert for AS2/HTTPS Send; IDENTITY_KEY = private key for SFTP" },
    "certificatePem": { "type": "string", "description": "Certificate content in PEM format (include -----BEGIN CERTIFICATE----- / -----END CERTIFICATE-----)" },
    "passphrase": { "type": "string", "description": "For identity key only; omit or empty for public cert" }
  },
  "required": ["partnerName", "certificateName", "certificateType", "certificatePem"]
}

ee:message.ee:set-payload:
%dw 2.0
output multipart/form-data
---
{
	parts: {
		certType: {
			headers: {
				"Content-Disposition": { name: "certType" }
			},
			content: if (vars.certificateType == "PUBLIC" or vars.certificateType == "IDENTITY_KEY") "PEM" else vars.certificateType
		},
		certName: {
			headers: {
				"Content-Disposition": { name: "certName" }
			},
			content: vars.certificateName
		},
		certFile: {
			headers: {
				"Content-Disposition": { name: "certFile", filename: "certificate.pem" },
				"Content-Type": "text/plain"
			},
			content: vars.certificatePem as Binary
		}
	}
}

mcp:tool-listener.mcp:parameters-schema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": ["partnerType", "partnerName", "identifiers", "contact"],
  "properties": {
    "partnerType": {
      "type": "string",
      "description": "Type of the partner",
      "enum": ["PARTNER", "THIRD_PARTY"]
    },
    "partnerName": {
      "type": "string",
      "description": "Name of the partner"
    },
    "identifiers": {
      "type": "array",
      "description": "List of identifiers for the partner",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["identifierCode", "value"],
        "properties": {
          "identifierCode": {
            "type": "string",
            "description": "Code or type of the identifier. For AS2, use \"AS2\" or \"AS2 ID\"."
          },
          "value": {
            "type": "string",
            "description": "Value of the identifier"
          }
        }
      }
    },
    "contact": {
      "type": "object",
      "required": ["name", "email"],
      "properties": {
        "name": {
          "type": "string",
          "description": "Name of the contact person or team"
        },
        "email": {
          "type": "string",
          "format": "email",
          "description": "Email address of the contact"
        },
        "phoneNumber": {
          "type": "string",
          "description": "Phone number of the contact"
        }
      }
    }
  },
  "additionalProperties": false
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": ["partnerName", "endpoints"],
  "properties": {
    "partnerName": {
      "type": "string",
      "description": "Name of the partner"
    },
    "endpoints": {
      "type": "array",
      "description": "List of communication endpoints for the partner",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["endpointName", "protocol", "direction"],
        "allOf": [
          {
            "if": { "properties": { "protocol": { "const": "as2" } }, "required": ["protocol"] },
            "then": {
              "required": ["hostAs2Identifier", "partnerAs2Identifier", "partnerAs2Url", "partnerCertificateId"],
              "properties": {
                "encryptionAlgorithm": { "type": "string", "enum": ["UNENCRYPTED", "AES128_CBC", "AES128_CCM", "AES128_GCM", "AES192_CBC", "AES192_CCM", "AES192_GCM", "AES256_CBC", "AES256_CCM", "AES256_GCM", "AES256_WRAP", "CAST5", "DES_EDE3", "RC2"] },
                "signatureAlgorithm": { "type": "string", "enum": ["UNSIGNED", "MD5", "SHA1", "SHA224", "SHA256", "SHA384", "SHA512"] },
                "enforceSecurity": { "type": "string", "enum": ["NONE", "SIGNED", "ENCRYPTED", "SIGNED_ENCRYPTED"] },
                "isAsyncMdn": { "type": "boolean" },
                "receiptDeliveryUrl": { "type": "string" }
              }
            }
          },
          {
            "if": { "properties": { "protocol": { "const": "sftp" } }, "required": ["protocol"] },
            "then": { "required": ["serverAddress", "port", "authType", "username", "password", "path"] }
          }
        ],
        "properties": {
          "endpointName": { "type": "string", "description": "Name of the endpoint" },
          "protocol": { "type": "string", "enum": ["sftp", "ftp", "http", "https", "as2"], "description": "Communication protocol" },
          "direction": { "type": "string", "enum": ["RECEIVE", "SEND"], "description": "Direction of data flow" },
          "description": { "type": "string", "description": "Endpoint description" },
          "serverAddress": { "type": "string", "description": "Server address for the endpoint (SFTP)" },
          "port": { "type": "integer", "description": "Port number (SFTP)" },
          "authType": { "type": "string", "enum": ["BASIC"], "description": "Authentication type (SFTP)" },
          "username": { "type": "string", "description": "Username for authentication (SFTP)" },
          "password": { "type": "string", "description": "Password for authentication (SFTP)" },
          "path": { "type": "string", "description": "Path on the server (SFTP)" },
          "supportedFormats": { "type": "string", "enum": ["EDI", "NON_EDI"], "description": "Supported file formats" },
          "pollingFrequency": { "type": ["integer", "null"], "description": "Polling frequency in milliseconds" },
          "sizeCheckWaitTime": { "type": ["integer", "null"], "description": "Wait time for size check in milliseconds" },
          "fileNamePattern": { "type": "string", "description": "Pattern for matching or generating filenames" },
          "hostAs2Identifier": { "type": "string", "description": "Your organization AS2 identifier" },
          "partnerAs2Identifier": { "type": "string", "description": "Partner AS2 identifier" },
          "partnerAs2Url": { "type": "string", "description": "Partner AS2 URL for send" },
          "partnerCertificateId": { "type": "string", "description": "UUID of partner certificate in Partner Manager" },
          "hostKeystoreId": { "type": "string", "description": "UUID of host keystore (AS2 Receive)" },
          "enforceSecurity": { "type": "string", "description": "Enforce security level for AS2 Receive" },
          "requireEncryptedMdn": { "type": "boolean", "description": "Require encrypted MDN (AS2 Receive)" },
          "mdnSignatureAlgorithm": { "type": "string", "description": "MDN signature algorithm" },
          "encryptionAlgorithm": { "type": "string", "description": "Encryption algorithm (AS2 Send)" },
          "signatureAlgorithm": { "type": "string", "description": "Signature algorithm (AS2 Send)" },
          "messageSubject": { "type": "string", "description": "MIME Subject header (AS2 Send)" },
          "requireMdn": { "type": "boolean", "description": "Request signed MDN receipt (AS2 Send)" },
          "isAsyncMdn": { "type": "boolean", "description": "Use asynchronous MDN (AS2 Send)" },
          "receiptDeliveryUrl": { "type": "string", "description": "URL for async MDN receipt (AS2 Send)" },
          "connectionTimeout": { "type": "integer", "description": "Connection timeout in milliseconds (AS2 Send)" },
          "retryInterval": { "type": "integer", "description": "Retry interval in seconds (AS2 Send)" },
          "maxRetryAttempts": { "type": "integer", "description": "Max retry attempts (AS2 Send)" },
          "apiManagerId": { "type": "string", "description": "API Manager instance ID (AS2 Receive, optional)" }
        }
      }
    }
  }
}
